7	      const result = runScenario({
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [
10	          {
11	            op: "quote",
12	            items: [
13	              { type: "sword", material: "steel", enchantment: 0, cursed: false },
14	            ],
15	          },
16	        ],
17	      });
