27	              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
28	            ],
29	          },
30	        ],
31	      });
32	      expect(result).toEqual({ results: [{ premium: 71 }] });
33	    });
34	    it("computes base premium for a single staff", () => {
35	      const result = runScenario({
36	        customer: { yearsWithMHPCO: 0 },
37	        steps: [
38	          {
39	            op: "quote",
