1	const premiumByItemType: Record<string, number> = {
2	  sword: 115,
3	  amulet: 71,
4	  staff: 93,
5	};
6	
7	export const runScenario = (scenario: any): unknown => {
8	  const itemType = scenario.steps[0].items[0].type;
9	  const premium = premiumByItemType[itemType];
10	  return { results: [{ premium }] };
11	};
